var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932: <color=#ffd34c>힐데</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932：<color=#ffd34c>ヒルデ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932: <color=#ffd34c>希爾德</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข FS001L0932: <color=#ffd34c>ฮิลเด้</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số FS001L0932: <color=#ffd34c>Hilde</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. FS001L0932: <color=#ffd34c>希尔德</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. FS001L0932: <color=#ffd34c>Hilde</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. FS001L0932\xA0: <color=#ffd34c>Hilde</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기분이 안 좋아 보이는군.","JPN":"顔色が悪いな。","ENG":"You don't look so well.","TWN":"你看起來心情很糟呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무슨 나쁜 소식이라도 있나?","JPN":"何か悪い知らせでもあるのか？","ENG":"Do you have bad news?","TWN":"是有什麼壞消息嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"생색내긴 그렇지만 내 덕분에 당분간 자금 걱정은 없을 텐데?","JPN":"恩を着せるわけじゃないが、私のおかげで当分の間、資金の心配もいらないだろ？","ENG":"I don't want to brag, but I've given you enough money.","TWN":"雖然沒有要施恩圖報的意思，但多虧有我，你暫時不用擔心資金問題了不是嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"몇 년 동안 감감무소식이던 말괄량이 아가씨도 돌아왔고 말이야.","JPN":"数年間、何の音沙汰もなかったじゃじゃ馬娘も戻って来たことだしな。","ENG":"And your naughty Master has finally come back after years of silence.","TWN":"況且，幾年來一直音訊全無的野丫頭也回來了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"왜 그렇게 위궤양 도진 사람 같은 표정을 짓고 있는지 모르겠군.","JPN":"なのに、なぜそんなしんどそうな顔をしてるんだ？","ENG":"I can't figure out why you look like someone who has a stomach ulcer.","TWN":"真不懂為什麼你一副像是得了胃潰瘍的表情。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......이게 다 누구 때문인데 아무것도 모른다는 듯이 가증스러운 표정을 짓고 계시는 거죠?","JPN":"……しらを切るのはやめてもらえますか？","ENG":"Are you serious? This is all because of you, and you're now acting like you don't know anything?","TWN":"……您也不想想是因為誰，還裝作什麼都不知道的樣子。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"스승님이 돌아오신 거야 물론 축하할 일이지만 그분 성격상 앞으로 제가 수습해야 할 사건, 사고도 만만치 않을 겁니다.","JPN":"師匠が戻って来たのはもちろん喜ばしいことですが、あの方の性格を考える限り、私が後始末をする事件や事故も、かなり増えるので。","ENG":"Of course I'm glad that Master is back. But considering her personality, I'll have to cover up all the troubles she will cause.","TWN":"師父能回來了，這當然是件值得慶祝的事情。但是以她的個性，我之後得善後的事件、事故應該不少吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그것만 생각해도 <color=#ff3636>[DATA EXPUNGED]</color> 때 잃어버린 눈알이 지끈지끈 쑤시는 판인데 보안감찰 대상에 포함이라니.......","JPN":"それだけでも<color=#ff3636>[DATA EXPUNGED]</color>の時に失った目がズキズキ痛むのに、保安観察対象に含まれるなんて……","ENG":"The eye I lost during the <color=#ff3636>[DATA EXPUNGED]</color> aches just by thinking about it. And I now have perform a secret inspection on her?","TWN":"光是用想的，我在<color=#ff3636>[DATA_EXPUNGED]</color>時失去的眼球就開始發痛，更別說她竟然是在保護監察對象當中。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"들키면 <color=#ff3636>[DATA EXPUNGED]</color> 님도 곱게 죽진 못할 겁니다.","JPN":"バレたら<color=#ff3636>[DATA EXPUNGED]</color>さんも、泣きをみることになりますよ。","ENG":"If Master finds out, you will meet a gruesome fate as well, <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"如果她被發現這件事，<color=#ff3636>[DATA_EXPUNGED]</color>可不只是死這麼簡單了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하, 안 들키면 되는 거지, 안 들키면.","JPN":"はは、バレなければいいんだよ。バレなければ。","ENG":"Hah hah, it's okay as long as we don't get caught.","TWN":"哈哈，不被發現就行了，不被發現的話。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네 사정도 모르는 바는 아니지만 이것도 필요한 절차라서 말이야.","JPN":"君の事情もわかるが、これも必要な手続きなんだ。","ENG":"I understand your situation, but this is a necessary procedure.","TWN":"雖然我不知道你的處境，但這是個必要的程序。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그리고 그녀가 무슨 생각을 하는지 알아 둘 필요가 있다는 건 자네도 동의하지 않았나?","JPN":"彼女が何を考えているのか知る必要がある。これには君も同意するだろ？","ENG":"And didn't you agree that we need to know what she's thinking about?","TWN":"而且，我們需要知道她在想什麼，這你不是也同意了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그건 그렇습니다만.","JPN":"……","ENG":"I did.","TWN":"……是沒錯啦。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좋아. 의견이 일치돼서 기쁘군.","JPN":"よし。意見が一致したようで嬉しいよ。","ENG":"Good. I'm glad we concur.","TWN":"很好，意見一致真是太好了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 보고를 시작하지.","JPN":"では、報告を始めてくれ。","ENG":"Start the briefing then.","TWN":"那麼，開始報告吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Okay.","TWN":"……好的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};